-- ── Teamwork ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Teamwork.com is a client-work and project management platform built for agencies, consultancies, and professional-services teams that need project planning, time tracking, and client billing in one connected system.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $9.99/user/month billed yearly)$q$, starting_price),
  founded_year = COALESCE(2007, founded_year),
  company_size = COALESCE($q$350-600 employees$q$, company_size),
  headquarters = COALESCE($q$Cork, Ireland$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Teamwork.com Review: Features, Pricing and Plans$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Teamwork.com offers agencies and client-services teams: project views, time tracking, client billing, pricing plans, and integrations.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Teamwork (Teamwork.com) is a project and client-work management platform founded in 2007 by Peter Coppinger and Daniel Mackey in Cork, Ireland, where the company remains headquartered. It is purpose-built for agencies, consultancies, and other professional-services teams that bill clients for time and need to manage multiple projects at once. The platform combines task management, Gantt-style timeline views, time tracking, resource and capacity planning, budgeting, invoicing, and client-facing proofing tools, plus an AI assistant called Teamwork AI. It integrates with tools such as HubSpot, QuickBooks, Xero, Slack, and Google Workspace. Pricing runs on a freemium model: a Free plan supports up to 5 users and 5 projects, while paid tiers include Basics (from about $9.99 per user per month billed yearly), Accelerate (from about $24.99 per user per month billed yearly) with budgeting and advanced automation, and custom-priced Optimize and Enterprise tiers with CRM integrations, resource scheduling by role, and SSO. Teamwork.com serves more than 20,000 teams across roughly 170 countries and has raised outside investment, including $70 million from Bregal Milestone in 2021, while remaining largely founder-led.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff2a2bb2-265f-4fb2-8b9b-06a77db11584';

