-- ── Tebra ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tebra is a healthcare practice management and EHR platform formed from the 2021 merger of Kareo and PatientPop, combining clinical, billing, and patient-growth tools for independent medical practices.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom quote, commonly reported from about $49/provider/month$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$1,000-1,100 employees$q$, company_size),
  headquarters = COALESCE($q$Corona del Mar, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tebra Review: Practice Management and EHR Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Tebra combines EHR, billing, scheduling, and patient-growth tools for independent practices. See features, pricing, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tebra is a digital healthcare technology company formed in November 2021 through the merger of Kareo, an EHR and medical billing company founded by Dan Rodrigues in 2004, and PatientPop, a practice growth and patient engagement platform based in Santa Monica, California. Tebra is headquartered in Corona del Mar, California, and is led by Kareo founder Dan Rodrigues as CEO. The platform serves independent healthcare practices, integrating electronic health records (EHR), practice management, medical billing and revenue cycle management, telehealth, online scheduling, patient engagement messaging, and practice marketing tools such as websites and reputation management, all in one connected system. As of the mid-2020s, Tebra reports serving over 140,000 healthcare providers covering more than 120 million patients in the United States, with roughly 1,000 to 1,100 employees. Tebra does not publish fixed public pricing; the company uses a custom-quote model based on the number of providers and modules selected, with reported real-world quotes ranging from roughly $49 to $799 per provider per month depending on whether a practice buys a single module or a full platform bundle such as Practice Essentials or Practice Automation. Additional costs include card payment processing fees and optional AI note-generation add-ons.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fdb22c7e-5eac-4888-bd83-48ca29adb96d';

