-- ── Technitium DNS Server ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Technitium DNS Server is a free, open-source, self-hosted authoritative and recursive DNS server for privacy, ad-blocking, and network-level DNS control, built with a browser-based admin console.$q$, short_description),
  pricing_model = COALESCE($q$free/open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Mumbai, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Technitium DNS Server: Free Self-Hosted DNS Software$q$, seo_title),
  seo_meta_description = COALESCE($q$Technitium DNS Server is a free, open-source, self-hosted DNS server with DNS-over-HTTPS, ad blocking, and a web admin console.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Technitium DNS Server is a free and open-source, cross-platform authoritative and recursive DNS server created by Shreyas Zare, a developer based in Mumbai, India, who also built the Technitium MAC Address Changer. The DNS server is distributed under the GNU GPLv3 license, meaning the full feature set, including recursive resolution, authoritative zone hosting, DNS-over-TLS, DNS-over-HTTPS (with HTTP/1.1, HTTP/2, and HTTP/3 support), and DNS-over-QUIC, is available at no cost with no paid or feature-limited edition. It ships with a browser-based web admin console, a built-in DHCP server for multiple networks, clustering support to manage several DNS server instances from one console, multi-user role-based access control, and TOTP-based two-factor authentication. Built on .NET, it is designed to run efficiently on modest hardware, from a Raspberry Pi to a commodity desktop PC, while handling high query volumes using asynchronous I/O. Common use cases include self-hosted network-wide ad and tracker blocking, private DNS resolution for home labs and small businesses, and privacy-focused alternatives to public DNS resolvers. As open-source software with no company behind it in the venture-funded sense, Technitium has no disclosed company size, funding, or enterprise pricing tiers; it is maintained as an independent open-source project with active GitHub development and a community blog documenting frequent releases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '324e805f-15ca-4f08-af33-49fee415253c';

