-- ── Teedy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Teedy is a lightweight, open-source document management system (formerly Sismics Docs) offering full-text search, OCR, encryption, and workflow tools, available as a free self-hosted app or a paid cloud service.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); cloud plans from about EUR 19/user/month$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Lyon, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$Simplified Chinese$q$, $q$Traditional Chinese$q$]::text[],
  seo_title = COALESCE($q$Teedy: Open-Source Document Management System$q$, seo_title),
  seo_meta_description = COALESCE($q$Teedy is a free, open-source document management system with OCR, encryption, and search, plus an optional paid cloud version.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Teedy is a lightweight, open-source document management system built by Sismics, a software company based in Lyon, France, and originally released as Sismics Docs before being rebranded to Teedy in 2016. It is built on Java with a modular Maven architecture and offers a responsive web interface, a REST API, and an Android client. Core features include OCR-based text extraction, 256-bit AES encryption, full-text search, granular user and group permissions, tagging, and basic workflow support. The self-hosted, open-source version is released under the GPL license and is completely free, including all features such as OCR and encryption, with the only cost being the infrastructure used to run it; a preconfigured Docker image is available, and it can run without external dependencies using an embedded H2 database, or with PostgreSQL for larger deployments. The project has been reported to scale to roughly one million documents in production use, and can be deployed on hardware ranging from a Raspberry Pi to Kubernetes clusters. Sismics also offers a commercial, hosted cloud version at teedy.io for teams that do not want to self-host, with pricing starting at roughly EUR 19 per user per month. Teedy's interface supports English, French, Simplified Chinese, and Traditional Chinese.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'aca7a829-e889-4429-ac20-146ff507188a';

