-- ── Teleport ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Teleport (goteleport.com) is an infrastructure identity and access security platform that replaces passwords, SSH keys, and static credentials with short-lived, cryptographically verified access to servers, Kubernetes, databases, and cloud consoles.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); paid plans from about $10/user/month$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$roughly 250-270 employees$q$, company_size),
  headquarters = COALESCE($q$Oakland, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Teleport: Infrastructure Access and Identity Security$q$, seo_title),
  seo_meta_description = COALESCE($q$Teleport secures access to servers, Kubernetes, databases, and cloud infrastructure with identity-based, credential-free access. See pricing and features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Teleport, built by the company originally named Gravitational and now doing business as Teleport, Inc., is an infrastructure identity and access security platform founded in 2015 by CEO Ev Kontsevoy, CTO Alexander (Sasha) Klizhentas, and COO Taylor Wakefield. Headquartered in Oakland, California, the company has raised roughly $169 million in funding from investors including Kleiner Perkins, Bessemer Venture Partners, Y Combinator, and Insight Partners, reaching unicorn status with a valuation around $1.1 billion in 2022. Teleport replaces passwords, SSH keys, API tokens, and static database credentials with short-lived, cryptographically signed certificates, providing zero trust, least-privileged access to Linux servers, Windows desktops, Kubernetes clusters, databases, internal web applications, cloud provider consoles (AWS, Azure, GCP), and, more recently, Model Context Protocol (MCP) servers used by AI agents. A free, open-source Community Edition (built on a modified Apache 2.0 license, with commercial-use restrictions for larger companies since version 16) covers core SSH, Kubernetes, and database access for hobbyists and small teams. Paid tiers include a Team plan reported around $10 per user per month and a Business plan reported around $18 per user per month, plus custom-priced Enterprise and self-hosted options for large organizations. Teleport reports more than 600 customers, including Elastic, Samsung, NASDAQ, and IBM, and employs roughly 250 to 270 people.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '621c1563-301c-4006-9dc0-beb9d7803b61';

