-- ── TeleportHQ ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$TeleportHQ is a low-code, AI-assisted visual web app builder based in Romania that lets users design interfaces visually and export production-ready code in frameworks like React, Vue, Next.js, and Angular.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid Professional plan from about $9/editor/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Cluj-Napoca, Romania$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$TeleportHQ: Low-Code Visual Web App Builder$q$, seo_title),
  seo_meta_description = COALESCE($q$TeleportHQ is a low-code visual builder that exports production-ready React, Vue, and HTML/CSS code. See features, pricing, and plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$TeleportHQ is a low-code, AI-assisted visual web app and website builder founded in 2017 by CEO Paul Brie and headquartered in Cluj-Napoca, Romania. Unlike closed no-code page builders, TeleportHQ focuses on generating clean, production-ready code that developers can export in multiple frameworks, including React, Vue, Next.js, Angular, and plain HTML/CSS, alongside Figma import and AI-assisted design generation. The company raised a 2.5 million dollar seed round in 2022 led by Tokyo-based One Capital, with co-financing from the European Fund for Regional Development. TeleportHQ offers a free plan that includes 3 projects, up to 10 code views or downloads, unlimited team collaborators, free hosting on a TeleportHQ subdomain, and access to the AI website builder and Figma integration. Paid plans start with Professional, priced at roughly 9 dollars per editor per month when billed annually (18 dollars per editor per month billed monthly), which unlocks unlimited projects, unlimited code exports, private projects, and video uploads. An Agency plan adds support for 10 or more custom domains, custom storage and bandwidth, and Vercel integration, while Enterprise pricing is custom and requires contacting sales. TeleportHQ is completely unrelated to Teleport (goteleport.com), a US-based infrastructure access security company; the two share a name but not a founding team, product, or company history.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2ecc0e88-527f-46f0-83e1-06163f665cdf';

