-- ── Tella ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Tella is an all-in-one screen recording and video creation tool for making product demos, tutorials, and courses, with built-in editing, transcription, and hosting.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$13/month per user (Pro plan)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$under 20 employees$q$, company_size),
  headquarters = COALESCE($q$Amsterdam, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Tella Review: Screen Recording Software Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Tella is an all-in-one screen recorder for demos and tutorials. See features, pricing plans, pros, and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Tella is an all-in-one screen recording and video creation tool founded in 2020 by Grant Shaddick and Michiel Westerbeek, built through Y Combinator and primarily based in Amsterdam, Netherlands, with additional presence in San Francisco. The product lets users record their screen, webcam, microphone, and system audio on Mac, Windows, and Chrome, then edit the resulting video directly in the browser with tools such as a timeline editor, transcript-based editing, automatic layouts, and visual effects, before hosting and sharing the video with an embedded player and analytics. It is aimed at founders, marketers, customer success and sales teams, and educators who need to quickly create product demos, tutorials, and course content without a dedicated video editor. Tella has raised a total of about 2.6 million dollars in funding. Pricing is subscription-based with no permanent free tier beyond a trial: the Pro plan is 13 dollars per user per month, the Premium plan is 19 dollars per user per month (both billed annually, roughly 50 percent cheaper than monthly billing), and a custom-priced Enterprise plan adds SSO, SCIM, and dedicated support. Premium adds custom domains, branding removal, 60 FPS export, and advanced analytics on top of Pro's unlimited recording, storage, 4K export, and support for over 100 languages in transcription.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b1850e50-e82f-45cf-a0c9-accb892735a7';

