-- ── Temporal ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Temporal is an open-source durable workflow orchestration platform that makes application code fault tolerant by automatically preserving and recovering execution state, available as a free self-hosted server or paid Temporal Cloud.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source, self-hosted); Temporal Cloud from about $100/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$350-520 employees$q$, company_size),
  headquarters = COALESCE($q$Seattle, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Temporal: Durable Workflow Orchestration Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Temporal is an open-source durable execution platform for fault-tolerant workflows. See features, SDKs, and Temporal Cloud pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Temporal is an open-source durable execution and workflow orchestration platform founded in 2019 by Maxim Fateev and Samar Abbas, both previously involved in building the Cadence workflow engine at Uber and earlier orchestration systems at AWS and Microsoft. The company, Temporal Technologies, is headquartered in Seattle, Washington, and has raised a total of about 350 million dollars in funding, including a 146 million dollar round in 2025 at a valuation of roughly 1.72 billion dollars, from investors including Tiger Global, Sequoia Capital, Index Ventures, and Amplify Partners. Temporal lets developers write application logic as ordinary code in languages including Go, Java, TypeScript, Python, PHP, Ruby, and .NET, while the Temporal service automatically captures execution state at every step; if a process fails, it resumes exactly where it left off without manual retry logic or complex error handling. The self-hosted, open-source server is free under the MIT license. Temporal Cloud is a managed, usage-based offering with four tiers: Essentials starting at about 100 dollars per month, Business starting at about 500 dollars per month, and custom-priced Enterprise and Mission Critical tiers, with usage billed per million actions once volume exceeds included plan allowances. Companies including Netflix, Datadog, Snap, Indeed, and Stripe use Temporal to orchestrate microservices, data pipelines, and, increasingly, AI agent workflows.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2efa5f1f-29da-4d6c-a300-8437c5445f15';

