INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Multiple project views$q$, $q$Switch between list, board, table, calendar, and Gantt-style timeline views for the same project data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Built-in time tracking$q$, $q$Log billable and non-billable hours with timers or manual entry, then convert tracked time directly into invoices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Client billing and invoicing$q$, $q$Generate and send invoices from tracked time and project budgets, with syncing to Xero and QuickBooks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Resource and capacity planning$q$, $q$Visualize team workload and availability to avoid over-booking staff across concurrent client projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Budgeting and profitability tracking$q$, $q$Track project budgets against actual hours and costs to see profitability in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Teamwork AI$q$, $q$AI-assisted summaries, status updates, and workflow suggestions built into paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Automation engine$q$, $q$Rule-based automations that trigger status changes, notifications, and task assignments, with monthly action limits by plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Client and proofing tools$q$, $q$Client users can be added for visibility, feedback, and file proofing without full team-member access.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Combines project management with native time tracking and invoicing, reducing the need for separate billing tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Strong fit for agencies and client-services teams managing many concurrent projects and budgets$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Multiple project views (Gantt, board, list, table) suit different planning styles on the same data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Resource and capacity planning tools help prevent team over-allocation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Generous free tier for very small teams to evaluate the platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Per-user pricing can get expensive for larger teams once advanced features are needed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Some advanced features such as CRM integration and multi-currency budgeting are locked behind custom-priced Optimize and Enterprise tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Automation actions are capped by plan, which can be limiting for heavy automation users on lower tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Interface has a learning curve for teams new to full-featured project management software$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Mobile app is generally reported as less capable than the desktop web experience$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$What is Teamwork.com used for$q$, $q$Teamwork.com is used for planning and tracking client-facing projects, including task management, time tracking, resource planning, budgeting, and invoicing, primarily by agencies and professional-services teams.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Does Teamwork.com have a free plan$q$, $q$Yes, Teamwork.com offers a Free plan for up to 5 users and 5 projects with core project views and a limited automation allowance.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$How much does Teamwork.com cost$q$, $q$Paid plans start at roughly $9.99 per user per month billed yearly for the Basics plan, with the Accelerate plan starting at roughly $24.99 per user per month billed yearly, and custom pricing for Optimize and Enterprise tiers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Who founded Teamwork.com$q$, $q$Teamwork.com was founded in 2007 by Peter Coppinger and Daniel Mackey in Cork, Ireland, where the company is still headquartered.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Does Teamwork.com support time tracking and invoicing$q$, $q$Yes, native time tracking, timesheets, and invoicing that syncs with Xero and QuickBooks are built into the platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Is Teamwork.com good for agencies$q$, $q$Teamwork.com is widely used by marketing, creative, and software agencies because it combines project delivery tracking with client billing and profitability reporting in one system.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Does Teamwork.com integrate with other tools$q$, $q$Yes, it integrates with tools such as HubSpot, QuickBooks, Xero, Slack, Google Workspace, and, on higher tiers, Salesforce and NetSuite.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$What is Teamwork AI$q$, $q$Teamwork AI is a set of AI-assisted features built into paid plans that help summarize project activity, draft status updates, and suggest workflow actions.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Agency client delivery$q$, $q$Agencies use Teamwork.com to plan client projects, track billable hours against budgets, and invoice clients directly from tracked time.$q$, $q$Marketing, creative, and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Software and IT consultancy delivery$q$, $q$Consultancies track project scope, resource allocation, and profitability across multiple concurrent client engagements.$q$, $q$Software and IT consulting firms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Internal cross-functional project management$q$, $q$Teams use Gantt and board views to plan internal initiatives, track dependencies, and manage team capacity without client billing.$q$, $q$Internal operations and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 5 users","Up to 5 projects","Core project views","100 automation actions per month","Basic time tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Basics$q$, $q$From about $9.99/user/month$q$, $q$billed yearly (monthly billing also available at a higher rate)$q$, NULL, $q$["Unlimited templates","Time tracking","Gantt, table, list, and board views","Teamwork AI basics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Accelerate$q$, $q$From about $24.99/user/month$q$, $q$billed yearly (monthly billing also available at a higher rate)$q$, NULL, $q$["Everything in Basics","Smart forms","Higher automation limits","Capacity planning and time budgets","HubSpot and QuickBooks integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Optimize$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Everything in Accelerate","Quotes","CRM pipeline integration","Resource scheduling by role or skill","Multi-currency budgeting","Salesforce and NetSuite integration"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Everything in Optimize","Single sign-on (SSO)","Dedicated customer success manager","Priority support","Advanced security enforcement"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$overview$q$, $q$What Is Teamwork.com$q$, 2, ARRAY[$q$Teamwork.com is a project management and client-work platform designed specifically for agencies, consultancies, and other teams that deliver billable work for external clients. Unlike general-purpose task tools, it bundles project planning with time tracking, budgeting, and invoicing so that client-facing teams can manage delivery and profitability from a single system.$q$, $q$Founded in 2007 by Peter Coppinger and Daniel Mackey in Cork, Ireland, the company grew as a bootstrapped business before taking a $70 million growth investment from Bregal Milestone in 2021. Teamwork.com now serves tens of thousands of teams worldwide, with particular strength among marketing agencies, software consultancies, and creative studios that need to track time against client budgets.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform offers multiple project views, including list, board (kanban), table, calendar, and Gantt-style timeline views, so teams can plan and track work in the format that suits them.$q$, $q$Built-in time tracking lets users log billable and non-billable hours, generate timesheets, and sync entries directly into client invoices, which is one of the features that differentiates Teamwork.com from generic project management tools.$q$, $q$Resource and capacity planning tools help managers see who is over or under allocated across active projects, while budgeting features track project profitability in real time.$q$, $q$Teamwork AI adds AI-assisted features such as automated status updates, summarization, and workflow suggestions across paid plans, alongside an automation engine with a monthly cap on automated actions that scales by plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff2a2bb2-265f-4fb2-8b9b-06a77db11584', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Teamwork.com uses a freemium pricing model with five tiers. The Free plan supports up to 5 users and 5 projects with core views and a limited automation allowance. The Basics plan starts at roughly $9.99 per user per month billed yearly and adds unlimited templates, time tracking, and additional views.$q$, $q$The Accelerate plan starts at roughly $24.99 per user per month billed yearly and unlocks smart forms, higher automation limits, capacity planning, time budgets, and integrations with HubSpot and QuickBooks. Optimize and Enterprise are custom-priced tiers aimed at larger organizations, adding CRM pipeline integration, multi-currency budgeting, Salesforce and NetSuite integration, single sign-on, and a dedicated customer success manager. Annual billing saves roughly 20 to 29 percent compared with monthly billing across paid tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Certified EHR$q$, $q$Clinical documentation, e-prescribing, and certified electronic health records supporting multiple specialties.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Medical billing and revenue cycle management$q$, $q$Insurance claims submission, patient payments, and denial management tools built into the platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Online scheduling and reminders$q$, $q$Patient-facing scheduling with automated appointment reminders to reduce no-shows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Telehealth$q$, $q$Integrated video visits as part of the Practice Essentials bundle.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Practice websites and marketing$q$, $q$Website building, search marketing, and online reputation management inherited from PatientPop.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Patient messaging and digital registration$q$, $q$Two-way patient messaging and digital intake forms to reduce front-desk paperwork.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$AI note generation$q$, $q$Optional AI-assisted clinical note generation available as a capped subscription or per-note add-on.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Provider-based pricing$q$, $q$Pricing is based on the number of clinical providers rather than total staff, so support staff can typically use the platform at no extra seat cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Combines EHR, billing, scheduling, and marketing in one platform, reducing the need for multiple vendors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Provider-based pricing means non-clinical staff can generally use the system without extra per-seat charges$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Strong practice-marketing toolset inherited from PatientPop, including websites and reputation management$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Serves a large base of independent practices, giving the platform mature, specialty-tested workflows$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Modular bundles let practices start with core needs and add modules over time$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$No published fixed pricing, so practices must go through a sales quote process to know exact costs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Reported pricing varies widely (roughly $49 to $799 per provider per month) depending on modules and negotiation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Payment processing and AI note generation are billed as additional costs on top of the base subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Some users report a learning curve when migrating from legacy Kareo or PatientPop-only setups to the unified platform$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$As with any merged platform, some legacy Kareo and PatientPop features have required time to fully integrate$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$What is Tebra$q$, $q$Tebra is a healthcare practice management and EHR platform formed in 2021 from the merger of Kareo and PatientPop, serving independent medical practices with clinical, billing, and patient-growth tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$How much does Tebra cost$q$, $q$Tebra uses custom quote-based pricing tied to the number of providers, with reported costs commonly ranging from about $49 to $799 per provider per month depending on the modules selected.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Is Tebra the same as Kareo$q$, $q$Kareo is one of the two companies, along with PatientPop, that merged in November 2021 to form Tebra. Kareo's EHR and billing technology now operates as part of the Tebra platform.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Does Tebra include an EHR$q$, $q$Yes, Tebra includes a certified electronic health record module for clinical documentation and e-prescribing alongside its billing and practice management tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Who founded Tebra$q$, $q$Tebra was formed by the 2021 merger of Kareo, founded by Dan Rodrigues in 2004, and PatientPop. Dan Rodrigues serves as CEO of Tebra.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Where is Tebra headquartered$q$, $q$Tebra is headquartered in Corona del Mar, California, United States.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Does Tebra charge per provider or per user$q$, $q$Tebra's pricing model is based on the number of clinical providers rather than total staff seats.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Does Tebra offer telehealth$q$, $q$Yes, telehealth is included as part of Tebra's Practice Essentials platform bundle.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Independent practice EHR and billing$q$, $q$Solo and small-group practices use Tebra to manage clinical documentation, insurance billing, and patient payments in one system.$q$, $q$Independent physicians and small medical groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Patient acquisition and growth$q$, $q$Practices use Tebra's website, search marketing, and reputation management tools to attract and retain patients.$q$, $q$Practice managers and marketing-focused clinics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Telehealth-enabled care delivery$q$, $q$Practices offering virtual visits use Tebra's integrated telehealth alongside scheduling and billing.$q$, $q$Multi-specialty and telehealth-forward practices$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Single solution$q$, $q$Custom quote$q$, $q$monthly per provider$q$, NULL, $q$["Choose one module such as billing or EHR alone","Lower entry cost for practices with a specific need"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Practice Essentials$q$, $q$Custom quote, reported around $149-$499/provider/month for full bundles$q$, $q$monthly per provider$q$, NULL, $q$["Medical billing","Clinical EHR","Telehealth"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$Practice Automation$q$, $q$Custom quote$q$, $q$monthly per provider$q$, NULL, $q$["Everything in Practice Essentials","Patient experience and engagement tools","Practice marketing and reputation management"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$overview$q$, $q$What Is Tebra$q$, 2, ARRAY[$q$Tebra is a healthcare technology platform for independent medical practices, formed in November 2021 when Kareo, an established EHR and medical billing company, merged with PatientPop, a practice-growth and patient-engagement platform. The combined company is headquartered in Corona del Mar, California, and is led by Kareo founder Dan Rodrigues as CEO.$q$, $q$The platform is designed to give independent practices the same operational and marketing capabilities as larger health systems, spanning clinical documentation, billing, scheduling, telehealth, and patient acquisition, without requiring practices to stitch together multiple point solutions.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tebra's EHR module supports clinical documentation, e-prescribing, and certified electronic health records for a range of specialties, alongside AI-assisted note generation as an add-on.$q$, $q$Billing and revenue cycle management tools handle insurance claims, patient payments, and denial management, with card payment processing available directly through Tebra Payments or via Stripe integration.$q$, $q$Patient engagement features include online scheduling, automated appointment reminders, digital patient registration, and two-way messaging.$q$, $q$Practice marketing tools carried over from PatientPop include practice websites, search marketing, and online reputation and review management, aimed at helping independent practices attract new patients.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fdb22c7e-5eac-4888-bd83-48ca29adb96d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tebra does not publish fixed public pricing tiers. Instead, pricing is quote-based and built around the number of clinical providers rather than total staff seats, meaning support staff can typically use the platform at no additional per-seat cost.$q$, $q$Practices can start with a single solution (such as billing or EHR alone) or choose a platform bundle: Practice Essentials, which combines billing, clinical EHR, and telehealth, or Practice Automation, which adds patient experience and engagement tools on top. Reported real-world quotes range from roughly $49 to $799 per provider per month depending on modules and practice size, with full-bundle quotes commonly falling between about $149 and $499 per provider per month. Card processing (2.75% plus $0.30 through Tebra Payments, or 2.9% plus $0.30 via Stripe) and optional AI note generation (around $99 per provider per month, or usage-based per note) are billed separately.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Recursive and authoritative DNS$q$, $q$Runs as both a recursive resolver and an authoritative server for hosting your own DNS zones.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Encrypted DNS protocols$q$, $q$Supports DNS-over-TLS, DNS-over-HTTPS, and DNS-over-QUIC for private, encrypted DNS resolution.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Web-based admin console$q$, $q$Browser-based interface for configuration, zone management, and monitoring, including a dark mode option.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Built-in DHCP server$q$, $q$Manages DHCP for multiple networks alongside DNS from the same application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Clustering$q$, $q$Manage two or more DNS Server instances from a single admin console for redundancy.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Ad and tracker blocking$q$, $q$Built-in support for blocklists to filter ads, trackers, and malicious domains network-wide.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Role-based access and 2FA$q$, $q$Multi-user accounts with role-based permissions and TOTP two-factor authentication.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$High-performance async architecture$q$, $q$Built on .NET with asynchronous I/O to handle high query volumes on commodity hardware.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Completely free and open source with no feature-limited paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Full encrypted DNS protocol support (DoT, DoH, DoQ) built in, not requiring third-party add-ons$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Web-based admin console makes it more approachable than many self-hosted DNS tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Combines DNS and DHCP server functionality in a single application$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Actively maintained with frequent releases and an engaged self-hosting community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Requires self-hosting and basic networking knowledge to deploy and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$No official enterprise support contracts or SLAs since it is a community-maintained open-source project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Documentation is community-driven and less polished than some commercial DNS platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Being a single-developer-led project, long-term roadmap depends on one maintainer's continued involvement$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Advanced features like clustering require more setup effort than plug-and-play SaaS DNS filtering tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Is Technitium DNS Server free$q$, $q$Yes, Technitium DNS Server is completely free and open source under the GNU GPLv3 license, with no paid tier or feature limits.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Who created Technitium DNS Server$q$, $q$Technitium DNS Server was created by Shreyas Zare, an independent developer based in Mumbai, India.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Can Technitium DNS Server block ads network-wide$q$, $q$Yes, it supports blocklists that filter ads, trackers, and malicious domains for every device on the network using it.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Does Technitium DNS Server support DNS-over-HTTPS$q$, $q$Yes, it supports DNS-over-HTTPS along with DNS-over-TLS and DNS-over-QUIC for encrypted DNS resolution.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$What platforms does Technitium DNS Server run on$q$, $q$It is a cross-platform application built on .NET and can run on Windows, Linux, macOS, and low-power devices such as a Raspberry Pi.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Does Technitium DNS Server include a DHCP server$q$, $q$Yes, it includes a built-in DHCP server capable of managing multiple networks.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Is Technitium DNS Server suitable for businesses$q$, $q$Yes, its GPLv3 license permits commercial use, and features like clustering and role-based access support small business and self-hosted enterprise use, though there is no official commercial support contract.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$How is Technitium DNS Server different from public resolvers like Cloudflare or Google DNS$q$, $q$Unlike third-party public resolvers, Technitium DNS Server is self-hosted, meaning the administrator controls the resolver, its logs, and its blocking rules directly rather than relying on an external provider.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Home network DNS and ad blocking$q$, $q$Self-hosters run Technitium on a home server or Raspberry Pi to block ads and trackers network-wide and gain visibility into DNS queries.$q$, $q$Home lab enthusiasts and privacy-focused individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Small business private DNS resolution$q$, $q$Small organizations self-host Technitium as an internal DNS resolver with encrypted DNS and DHCP management.$q$, $q$Small business IT administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Authoritative DNS hosting for personal domains$q$, $q$Users host their own DNS zones for personal or project domains without relying on a third-party DNS provider.$q$, $q$Developers and system administrators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$one-time, self-hosted$q$, NULL, $q$["Full recursive and authoritative DNS","DNS-over-TLS, DNS-over-HTTPS, DNS-over-QUIC","Built-in DHCP server","Clustering","Role-based access and 2FA","Ad and tracker blocking"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$overview$q$, $q$What Is Technitium DNS Server$q$, 2, ARRAY[$q$Technitium DNS Server is a free, open-source DNS server that individuals and organizations can self-host for privacy, security, and network-level control over DNS resolution. It functions as both an authoritative DNS server for hosting your own zones and a recursive resolver for answering queries on behalf of client devices.$q$, $q$The project was created by Shreyas Zare, an independent developer based in Mumbai, India, who has maintained Technitium's suite of networking tools, including the DNS server and the earlier Technitium MAC Address Changer, since the mid-2000s. The DNS server itself has been actively developed with frequent releases documented on the Technitium blog.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The server works out of the box with minimal configuration and includes a browser-based web admin console for managing zones, forwarders, and blocklists without editing configuration files by hand.$q$, $q$It supports encrypted DNS protocols including DNS-over-TLS, DNS-over-HTTPS (HTTP/1.1, HTTP/2, and HTTP/3), and DNS-over-QUIC, letting administrators run their own encrypted DNS endpoint rather than relying on third-party resolvers.$q$, $q$A built-in DHCP server can manage multiple networks, and a clustering feature allows several DNS server instances to be administered from a single console for redundancy and load distribution.$q$, $q$Security features include multi-user, role-based access control, non-expiring API tokens for automation, and TOTP-based two-factor authentication for admin accounts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Technitium DNS Server is entirely free and released under the GNU GPLv3 open-source license, which permits both personal and commercial use. There is no paid tier, license key, or feature gate; every capability, including clustering, DHCP, and encrypted DNS protocols, is available in the free download.$q$, $q$Because it is self-hosted, the only ongoing cost is the infrastructure used to run it, such as a home server, Raspberry Pi, virtual machine, or cloud instance. Users who redistribute modified versions of the software are required under GPLv3 to make their source code changes available under the same license.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('324e805f-15ca-4f08-af33-49fee415253c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$OCR text extraction$q$, $q$Automatically extracts searchable text from scanned documents and images.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$256-bit AES encryption$q$, $q$Encrypts stored documents to protect sensitive files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Full-text search$q$, $q$Indexes document content and metadata for fast retrieval across large archives.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Granular permissions$q$, $q$User and group-based access control for documents and folders.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$REST API$q$, $q$Programmatic access for integrating Teedy with other systems and custom workflows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Android client$q$, $q$Native mobile app for accessing and uploading documents on the go.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Docker-first deployment$q$, $q$Preconfigured Docker image with OCR and media conversion tools included, ready to run on port 8080.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Tagging and workflow tools$q$, $q$Organize documents with tags and route them through basic approval or review workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Free and open source under GPL with no feature limitations on the self-hosted version$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Includes enterprise-style features like OCR and encryption typically found only in paid document management systems$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Lightweight enough to run on modest hardware such as a Raspberry Pi, while also scaling to Kubernetes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Docker-first deployment makes self-hosting straightforward$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Optional hosted cloud version available for teams that do not want to manage infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Self-hosting requires basic server administration skills to deploy, secure, and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Smaller ecosystem and community compared to larger commercial document management platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Default embedded H2 database is best suited for smaller deployments; PostgreSQL is recommended for scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Mobile experience is limited to an Android client, with no native iOS app confirmed$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Cloud version pricing and feature parity with self-hosted may vary and require checking current plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Is Teedy free$q$, $q$Yes, the self-hosted, open-source version of Teedy is free under the GPL license. Sismics also offers an optional paid cloud version starting at roughly EUR 19 per user per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$What was Teedy called before$q$, $q$Teedy was originally released as Sismics Docs before being rebranded to Teedy in 2016.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Does Teedy support OCR$q$, $q$Yes, Teedy extracts text from scanned documents and images using OCR so they become searchable.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Can Teedy be self-hosted$q$, $q$Yes, Teedy is designed to be self-hosted using a Docker image, and can run on hardware ranging from a Raspberry Pi to Kubernetes clusters.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$What database does Teedy use$q$, $q$Teedy uses an embedded H2 database by default if no external database is configured, and supports PostgreSQL for larger deployments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Does Teedy have a mobile app$q$, $q$Teedy offers a native Android client for mobile access to documents.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Who develops Teedy$q$, $q$Teedy is developed by Sismics, a software company based in Lyon, France.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$What languages does Teedy support$q$, $q$Teedy's interface supports English, French, Simplified Chinese, and Traditional Chinese.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Small business document archiving$q$, $q$Small teams self-host Teedy to digitize, OCR, and organize business documents like invoices and contracts.$q$, $q$Small businesses and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Personal document management$q$, $q$Individuals self-host Teedy on a home server or Raspberry Pi to organize personal records with search and encryption.$q$, $q$Individuals and home-lab users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Team knowledge and file repository$q$, $q$Teams use Teedy's permissions, tagging, and workflow features to manage shared documents and approvals.$q$, $q$Small to mid-sized teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$one-time, self-hosted$q$, NULL, $q$["Full OCR and encryption","Full-text search","Granular permissions","REST API","Docker deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$Teedy Cloud$q$, $q$From about EUR 19/user/month$q$, $q$monthly$q$, NULL, $q$["Hosted, managed infrastructure","Same core document management features","No self-hosting required"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$overview$q$, $q$What Is Teedy$q$, 2, ARRAY[$q$Teedy is a lightweight, open-source document management system created by Sismics, a software company based in Lyon, France. It began life as Sismics Docs and was rebranded to Teedy in 2016, though the underlying open-source project remains hosted on GitHub under the sismics/docs repository.$q$, $q$The system is designed to bring enterprise-grade document management features, such as OCR, encryption, and full-text search, to individuals and small businesses without the cost of large proprietary document management platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Teedy automatically extracts text from scanned documents and images using OCR, making uploaded files searchable even when they originate as scans or photos.$q$, $q$Documents can be encrypted with 256-bit AES encryption, and access is controlled through granular user and group permission settings.$q$, $q$A full-text search engine indexes document content and metadata, letting users quickly locate files across large document sets.$q$, $q$The platform includes tagging, basic workflow and routing support, a REST API for integrations, and a native Android client for mobile access.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The self-hosted, open-source version of Teedy is completely free under the GPL license, including every feature such as OCR, encryption, and workflow tools. Users only pay for the infrastructure needed to host it, whether that is a home server, a Raspberry Pi, or a cloud virtual machine, and a preconfigured Docker image is available to simplify deployment.$q$, $q$For teams that prefer not to manage their own infrastructure, Sismics also offers a commercial, hosted cloud version of Teedy at teedy.io, with published pricing starting at roughly EUR 19 per user per month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('aca7a829-e889-4429-ac20-146ff507188a', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Certificate-based access$q$, $q$Replaces passwords, SSH keys, and API tokens with short-lived, cryptographically signed certificates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Unified infrastructure access$q$, $q$Single platform for accessing Linux servers, Windows desktops, Kubernetes clusters, databases, and internal web apps.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Cloud console access$q$, $q$Secure, credential-free access to AWS, Azure, and GCP consoles and APIs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Session recording and audit logs$q$, $q$Records sessions and logs access activity for security review and compliance audits.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Zero trust, least-privileged access$q$, $q$Grants ephemeral, scoped access rather than standing privileged credentials.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Open-source Community Edition$q$, $q$Free self-hosted edition covering core SSH, Kubernetes, and database access for small-scale use.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$MCP server access control$q$, $q$Extends identity-based access controls to Model Context Protocol servers used by AI agents.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Single sign-on integration$q$, $q$Integrates with identity providers for centralized authentication across infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Eliminates static credentials like SSH keys and passwords in favor of short-lived certificates, reducing credential-theft risk$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Covers a very broad range of infrastructure types (servers, Kubernetes, databases, cloud consoles, web apps) in one platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Free, open-source Community Edition available for small teams, hobbyists, and evaluation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Detailed session recording and audit logs simplify security compliance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Backed by well-known investors and used by large enterprises, indicating platform maturity$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Full public pricing is not published; getting an exact quote requires contacting sales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Community Edition's free commercial use is restricted to companies under 100 employees and under $10 million in annual revenue as of version 16$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Self-hosted Enterprise deployments can involve significant annual contract minimums for larger organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Initial setup and infrastructure onboarding can require meaningful engineering effort for complex environments$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$As a security-critical system, misconfiguration carries higher operational risk than lower-stakes SaaS tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$What is Teleport used for$q$, $q$Teleport is used to provide secure, credential-free access to infrastructure such as servers, Kubernetes clusters, databases, cloud consoles, and internal applications using short-lived certificates instead of passwords or static keys.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Is Teleport free$q$, $q$Teleport offers a free, open-source Community Edition for small-scale and personal use. Paid Team, Business, and Enterprise plans add additional features, support, and higher usage limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Who founded Teleport$q$, $q$Teleport was founded in 2015 by Ev Kontsevoy, Alexander (Sasha) Klizhentas, and Taylor Wakefield, and is headquartered in Oakland, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Is Teleport the same company as TeleportHQ$q$, $q$No. Teleport (goteleport.com) is an infrastructure access and identity security company, while TeleportHQ (teleporthq.io) is an unrelated no-code visual web app builder based in Romania.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$How much does Teleport cost$q$, $q$Teleport's paid plans are usage-based; reported pricing starts around $10 per user per month for a Team-level plan, with Business and Enterprise tiers priced higher or custom-quoted.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Does Teleport support Kubernetes access$q$, $q$Yes, Teleport provides zero trust access to Kubernetes clusters alongside servers, databases, and cloud consoles.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Can Teleport secure AI agent access to infrastructure$q$, $q$Yes, Teleport has extended its access model to Model Context Protocol (MCP) servers, applying the same identity-based controls to AI agents.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$How much funding has Teleport raised$q$, $q$Teleport has raised roughly $169 million in funding, reaching a valuation of about $1.1 billion in 2022.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Zero trust infrastructure access$q$, $q$Engineering teams replace SSH keys and static credentials with Teleport's short-lived certificates for accessing servers and Kubernetes.$q$, $q$DevOps and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Compliance-driven access auditing$q$, $q$Security teams use Teleport's session recording and audit logs to meet compliance requirements around privileged access.$q$, $q$Security and compliance teams at regulated companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Secure AI agent infrastructure access$q$, $q$Organizations apply Teleport's identity controls to MCP servers so AI agents access infrastructure under the same least-privilege model as humans.$q$, $q$Platform teams deploying AI agents in production$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Community Edition$q$, $q$Free$q$, $q$self-hosted$q$, NULL, $q$["Core SSH, Kubernetes, and database access","Open-source, modified Apache 2.0 license","Free for personal and hobby use; restricted commercial use for larger companies"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Team$q$, $q$Reported around $10/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Cloud-hosted management","Core access features for small teams","Usage-based pricing on active users and resources"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Business$q$, $q$Reported around $18/user/month$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Team","Additional integrations and controls","Higher usage limits"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Self-hosted or cloud-hosted options","Advanced security and compliance features","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$overview$q$, $q$What Is Teleport$q$, 2, ARRAY[$q$Teleport is an infrastructure identity and access security platform, sometimes categorized as privileged access management (PAM), that lets organizations grant employees, services, and now AI agents secure access to servers, cloud consoles, databases, and internal applications without relying on static, long-lived credentials.$q$, $q$The company was founded in 2015 by Ev Kontsevoy, Alexander (Sasha) Klizhentas, and Taylor Wakefield, and is headquartered in Oakland, California. It began as an open-source project (originally under the name Gravitational) and has grown into a venture-backed company valued at roughly $1.1 billion, used by more than 600 customers including Elastic, Samsung, NASDAQ, and IBM.$q$, $q$Note: Teleport (goteleport.com) is an entirely separate company from TeleportHQ (teleporthq.io), a no-code visual web app builder based in Romania. Despite the similar name, the two products, companies, and founding teams are unrelated.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Teleport issues short-lived, cryptographically signed certificates instead of passwords or long-lived SSH keys and API tokens, minimizing the risk of credential theft or sprawl.$q$, $q$It provides unified, zero trust access to a broad set of infrastructure, including Linux servers, Windows desktops, Kubernetes clusters, databases, internal web apps, and cloud provider APIs and consoles for AWS, Azure, and GCP.$q$, $q$Session recording and detailed audit logging give security teams visibility into exactly who accessed what infrastructure and when, simplifying compliance audits.$q$, $q$Newer capabilities extend Teleport's access model to Model Context Protocol (MCP) servers, letting organizations apply the same identity-based access controls to AI agents interacting with infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('621c1563-301c-4006-9dc0-beb9d7803b61', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Teleport offers a free, open-source Community Edition suitable for hobbyists, homelabs, and small-scale self-hosted deployments. As of Teleport 16, Community Edition builds carry a modified Apache 2.0 commercial license that restricts free commercial use to companies with fewer than 100 employees and less than $10 million in annual revenue; individuals can use it for personal or hobby purposes without restriction.$q$, $q$Paid plans are usage-based, charging for active users and protected resources. Reported list pricing for a Team-level plan is around $10 per user per month, with a Business-level plan around $18 per user per month. Enterprise and self-hosted deployments for larger organizations use custom pricing, and exact current pricing requires contacting Teleport's sales team or requesting the published pricing guide.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Visual drag-and-drop editor$q$, $q$Design web interfaces visually without writing code from scratch.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Multi-framework code export$q$, $q$Export production-ready code in React, Vue, Next.js, Angular, or plain HTML and CSS.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Figma import$q$, $q$Import existing Figma designs directly into TeleportHQ to speed up design-to-code handoff.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$AI website builder$q$, $q$Generate initial page layouts and components from text prompts using built-in AI.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Free subdomain hosting$q$, $q$Publish projects instantly on a TeleportHQ subdomain without extra setup.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Team collaboration$q$, $q$Unlimited collaborators supported even on the free plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Custom domain publishing$q$, $q$Connect custom domains on paid plans, with support for 10 or more domains on the Agency plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Vercel integration$q$, $q$Deploy exported projects directly through Vercel on the Agency plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Exports genuinely production-ready, framework-native code rather than locking users into a proprietary format$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Generous free plan includes unlimited team collaborators and AI website generation$q$, 1);
