INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Figma import streamlines the handoff from design tools into working code$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Affordable entry-level paid plan compared to many design-to-code competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Free plan limits projects to 3 and code exports to 10, which can be restrictive for active users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Smaller company and community compared to larger no-code platforms, which may mean fewer third-party integrations$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Name similarity to the unrelated company Teleport (goteleport.com) can cause confusion in search results$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Advanced hosting features like multiple custom domains require the higher-priced Agency plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$AI-generated layouts typically require manual refinement before they are production-ready$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$What is TeleportHQ used for$q$, $q$TeleportHQ is used to visually design web interfaces and export the result as production-ready code in frameworks such as React, Vue, Next.js, Angular, or plain HTML and CSS.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Is TeleportHQ free$q$, $q$Yes, TeleportHQ offers a free plan with 3 projects, up to 10 code views or downloads, unlimited collaborators, and free subdomain hosting, with no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Is TeleportHQ the same company as Teleport (goteleport.com)$q$, $q$No, they are completely unrelated companies. TeleportHQ is a Romania-based no-code visual web app builder, while Teleport (goteleport.com) is a US-based infrastructure access security company.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Who founded TeleportHQ$q$, $q$TeleportHQ was founded in 2017 by CEO Paul Brie and is headquartered in Cluj-Napoca, Romania.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$What code does TeleportHQ export$q$, $q$TeleportHQ exports production-ready code in React, Vue, Next.js, Angular, and plain HTML and CSS.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Does TeleportHQ integrate with Figma$q$, $q$Yes, TeleportHQ supports importing designs directly from Figma into its visual editor.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$How much does TeleportHQ cost$q$, $q$The Professional plan costs roughly 9 dollars per editor per month billed annually, or 18 dollars per editor per month billed monthly. An Agency plan and custom Enterprise pricing are also available.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Has TeleportHQ raised funding$q$, $q$Yes, TeleportHQ raised a 2.5 million dollar seed round in 2022 led by One Capital, with co-financing from the European Fund for Regional Development.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Rapid front-end prototyping$q$, $q$Designers and developers use TeleportHQ to visually prototype interfaces and export working framework code quickly.$q$, $q$Front-end developers and product designers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Marketing site and landing page creation$q$, $q$Small teams build and publish marketing sites and landing pages without a full development cycle.$q$, $q$Startups and marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Design-to-code handoff$q$, $q$Teams import Figma designs into TeleportHQ to accelerate handoff from design to production-ready code.$q$, $q$Design and engineering teams collaborating on UI builds$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["3 projects","Up to 10 code views or downloads","Unlimited team collaborators","Free hosting on TeleportHQ subdomain","AI website builder and Figma integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Professional$q$, $q$About $9/editor/month billed annually ($18/editor/month billed monthly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited projects","Unlimited code views and downloads","Unlimited view-only collaborators","Video uploads","Private projects","Dedicated customer support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Agency$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Everything in Professional","10 or more custom domains","Custom storage options","Custom bandwidth on demand","Vercel integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Custom quote from sales team","Tailored features for large organizations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$overview$q$, $q$What Is TeleportHQ$q$, 2, ARRAY[$q$TeleportHQ is a low-code, AI-assisted platform for visually designing web interfaces and exporting the resulting layouts as production-ready front-end code. It is aimed at designers, developers, and entrepreneurs who want to move quickly from design to shippable code without being locked into a proprietary hosting format.$q$, $q$The company was founded in 2017 by CEO Paul Brie and is headquartered in Cluj-Napoca, Romania. TeleportHQ describes its mission as making user interface creation more accessible through automation and AI, drawing on the founding team's front-end development background. In 2022, the company raised a 2.5 million dollar seed round led by Tokyo-based One Capital, with additional co-financing from the European Fund for Regional Development.$q$, $q$Note: TeleportHQ (teleporthq.io) is a completely separate, unrelated company from Teleport (goteleport.com), a US infrastructure access and identity security platform. The two products share only a similar name.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users build interfaces with a visual, drag-and-drop editor and can import existing designs directly from Figma to speed up the handoff between design and code.$q$, $q$An AI website builder can generate initial layouts and components from prompts, which users can then refine visually before exporting.$q$, $q$TeleportHQ exports clean, production-ready code in multiple frameworks, including React, Vue, Next.js, Angular, and plain HTML and CSS, rather than locking output into a single proprietary format.$q$, $q$Projects can be published directly on a TeleportHQ subdomain for quick previews, or connected to custom domains and platforms like Vercel on higher-tier plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$TeleportHQ offers a free plan with no credit card required, including 3 projects, up to 10 code views or downloads, unlimited collaborators, and free hosting on a TeleportHQ subdomain, along with access to the AI website builder and Figma integration and an allotment of AI tokens for generation.$q$, $q$The Professional plan costs roughly 9 dollars per editor per month when billed annually, or 18 dollars per editor per month billed monthly, and adds unlimited projects, unlimited code exports, private projects, and video uploads. The Agency plan supports businesses managing many projects or domains, adding 10 or more custom domains, custom storage and bandwidth, and Vercel integration. Enterprise pricing is custom and requires contacting TeleportHQ's sales team.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2ecc0e88-527f-46f0-83e1-06163f665cdf', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
