INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$4K and 60 FPS export$q$, $q$Supports up to 4K resolution export, with 60 FPS export available on the Premium plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Built-in video hosting$q$, $q$Hosts finished videos with an embedded player, removing the need for a separate hosting service.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Custom domains and branding removal$q$, $q$Premium and Enterprise plans support custom domains and removing Tella branding from shared videos.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Multi-language transcription$q$, $q$Automatic transcription supports more than 100 languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Video analytics$q$, $q$Tracks view counts, watch history, and, on Premium, traffic sources for shared videos.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$All-in-one workflow combining recording, editing, hosting, and sharing without separate tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Transcript-based editing makes cutting and rearranging footage fast and approachable for non-editors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Supports 4K export and multi-language transcription even on the entry-level paid plan$q$, 2);
