INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$SSO and SCIM are only available on the custom-priced Enterprise plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Primarily focused on screen and webcam recording rather than full-featured video editing for complex projects$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$What is Tella used for$q$, $q$Tella is used to record and edit screen, webcam, and audio content for product demos, tutorials, onboarding videos, and course content.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Does Tella have a free plan$q$, $q$Tella does not offer a permanent free plan; it offers a trial period before requiring a Pro, Premium, or Enterprise subscription.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$How much does Tella cost$q$, $q$Tella's Pro plan is 13 dollars per user per month and the Premium plan is 19 dollars per user per month, both with a discount for annual billing; Enterprise pricing is custom.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Who founded Tella$q$, $q$Tella was founded in 2020 by Grant Shaddick and Michiel Westerbeek, and went through Y Combinator.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Where is Tella based$q$, $q$Tella's team is primarily based in Amsterdam, Netherlands, with additional presence reported in San Francisco, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Does Tella support 4K recording$q$, $q$Yes, Tella supports up to 4K export on its Pro plan, with 60 FPS export added on the Premium plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Can Tella remove its own branding from videos$q$, $q$Branding removal is available on the Premium and Enterprise plans, not on the Pro plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Does Tella support transcript-based editing$q$, $q$Yes, Tella lets users edit videos by editing the automatically generated transcript, and supports transcription in more than 100 languages.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Product demo creation$q$, $q$Founders and product teams record and edit polished product demo videos for websites, sales, and social media.$q$, $q$Startup founders and product marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Customer onboarding and tutorials$q$, $q$Customer success teams create step-by-step tutorial videos to help users adopt a product.$q$, $q$Customer success and support teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Course and training content$q$, $q$Educators and internal trainers record and edit lesson or training videos with transcript-based editing.$q$, $q$Course creators and internal L&D teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Pro$q$, $q$$13/user/month$q$, $q$monthly (about 50 percent off with annual billing)$q$, NULL, $q$["Unlimited video creation and storage","Screen, webcam, microphone, and system audio recording","Transcription in over 100 languages","4K export","Team collaboration and basic analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Premium$q$, $q$$19/user/month$q$, $q$monthly (about 50 percent off with annual billing)$q$, NULL, $q$["Everything in Pro","Custom domain setup","Removal of Tella branding","60 FPS export","Advanced analytics with traffic source tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Everything in Premium","SSO and SCIM authentication","Shared Slack channel with Tella team","Personalized onboarding"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$overview$q$, $q$What Is Tella$q$, 2, ARRAY[$q$Tella is an all-in-one screen recording and video creation tool built for people who need to produce polished product demos, tutorials, and course content without learning a full video editing application. It combines recording, editing, hosting, and sharing in a single browser-based workflow.$q$, $q$The company was founded in 2020 by Grant Shaddick and Michiel Westerbeek and went through Y Combinator. Tella's team is primarily based in Amsterdam, Netherlands, with reported additional presence in San Francisco, California, and has raised roughly 2.6 million dollars in total funding.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Tella records screen, webcam, microphone, and system audio simultaneously on Mac, Windows, and in Chrome, giving creators flexible source combinations for demos and tutorials.$q$, $q$Built-in editing tools include a timeline editor, transcript-based editing (cutting video by editing the text transcript), automatic camera and screen layouts, and visual effects, all without leaving the browser.$q$, $q$Recordings can be exported at up to 4K resolution on paid plans, and Premium adds 60 FPS export for smoother motion capture.$q$, $q$Finished videos are hosted directly on Tella with an embedded player, view analytics, and, on higher tiers, custom domains and removal of Tella branding.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b1850e50-e82f-45cf-a0c9-accb892735a7', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Tella does not offer a permanent free plan; new users get a trial period before choosing a paid plan. The Pro plan costs 13 dollars per user per month, with roughly 50 percent off available on annual billing, and includes unlimited video creation and storage, full recording capabilities, transcription support in over 100 languages, and 4K export.$q$, $q$The Premium plan costs 19 dollars per user per month (also with an annual discount) and adds custom domain setup, domain restriction controls, removal of Tella branding, 60 FPS export, and advanced analytics with traffic source tracking. An Enterprise plan offers custom pricing with volume discounts, adding SSO and SCIM authentication, a shared Slack channel with the Tella team, and personalized onboarding.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Durable execution$q$, $q$Automatically preserves workflow state so execution can resume exactly where it left off after a failure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Multi-language SDKs$q$, $q$Official SDKs for Go, Java, TypeScript, Python, PHP, Ruby, and .NET support polyglot teams.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Event history and replay$q$, $q$Records every workflow step, enabling precise recovery without custom error-handling code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Workflows and Activities model$q$, $q$Orchestrates external calls through Activities, coordinated by durable Workflow functions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Signals, Queries, and Updates$q$, $q$Supports long-running, human-in-the-loop workflows that react to external events over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Self-hosted open source server$q$, $q$Free, MIT-licensed server that organizations can run on their own infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Temporal Cloud$q$, $q$Fully managed, usage-based hosted offering with tiered plans and support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$AI agent orchestration$q$, $q$Increasingly used to orchestrate multi-step, fault-tolerant AI agent workflows in production.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Removes the need to hand-write complex retry, timeout, and recovery logic for distributed systems$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Free, open-source self-hosted option under the MIT license with no licensing cost$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Broad language support (Go, Java, TypeScript, Python, PHP, Ruby, .NET) fits polyglot engineering teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Built by the team behind Uber's Cadence engine, with deep experience in production workflow orchestration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Adopted by well-known companies (Netflix, Datadog, Snap, Stripe) validating production scalability$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Self-hosting the open-source server is operationally demanding and requires dedicated engineering effort$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Temporal Cloud usage-based pricing can become expensive at high action volumes without careful monitoring$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Learning curve exists around Temporal's Workflow and Activity programming model for teams new to durable execution$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Enterprise and Mission Critical tiers require a custom sales quote rather than transparent published pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Best suited to engineering-heavy organizations; less approachable for non-technical or very small teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$What is Temporal used for$q$, $q$Temporal is used to build fault-tolerant, durable workflows and microservice orchestration, ensuring application code recovers automatically from failures without custom retry logic.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Is Temporal free$q$, $q$Yes, Temporal's core server is free and open source under the MIT license and can be self-hosted at no licensing cost. Temporal Cloud is a paid, managed alternative.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Who founded Temporal$q$, $q$Temporal was founded in 2019 by Maxim Fateev and Samar Abbas, who previously built the Cadence workflow engine at Uber.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$What programming languages does Temporal support$q$, $q$Temporal offers official SDKs for Go, Java, TypeScript, Python, PHP, Ruby, and .NET.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$How much does Temporal Cloud cost$q$, $q$Temporal Cloud starts with an Essentials plan at about 100 dollars per month and a Business plan at about 500 dollars per month, with custom pricing for Enterprise and Mission Critical tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$What is durable execution$q$, $q$Durable execution is a technique where a system automatically preserves the state of running code so it can resume exactly where it left off after a crash or failure, without manual recovery logic.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Where is Temporal headquartered$q$, $q$Temporal Technologies is headquartered in Seattle, Washington, United States.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Is Temporal used for AI agent workflows$q$, $q$Yes, Temporal is increasingly used to orchestrate multi-step, fault-tolerant AI agent workflows in production, in addition to traditional microservice orchestration.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Microservices orchestration$q$, $q$Engineering teams use Temporal to coordinate calls across multiple microservices with automatic failure recovery.$q$, $q$Backend and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Long-running business processes$q$, $q$Companies use Temporal to model long-running processes like order fulfillment or onboarding that span minutes to months.$q$, $q$Companies with complex, multi-step business workflows$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$AI agent workflow orchestration$q$, $q$Teams building AI agents use Temporal to make multi-step agent workflows fault tolerant and resumable.$q$, $q$AI and machine learning engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$self-hosted, MIT license$q$, NULL, $q$["Full durable execution engine","All official SDKs","No licensing cost","Operational overhead is the user's responsibility"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Temporal Cloud Essentials$q$, $q$From about $100/month$q$, $q$monthly, usage-based above included allowance$q$, NULL, $q$["Includes an allotment such as 1 million Actions per month","1 GB active storage","40 GB retained storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Temporal Cloud Business$q$, $q$From about $500/month$q$, $q$monthly, usage-based above included allowance$q$, NULL, $q$["Higher included usage than Essentials","Additional support options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Temporal Cloud Enterprise$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Custom usage tiers","Enhanced support and SLAs"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$Temporal Cloud Mission Critical$q$, $q$Custom$q$, $q$annual contract$q$, NULL, $q$["Highest tier of support and reliability guarantees","Designed for mission-critical production workloads"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$overview$q$, $q$What Is Temporal$q$, 2, ARRAY[$q$Temporal is an open-source platform for durable execution, a technique that makes application code resilient to failures by automatically preserving its execution state. Instead of writing custom retry logic, timers, and recovery code, developers write workflows as ordinary functions in a general-purpose language, and the Temporal service guarantees that execution can resume exactly where it left off after a crash, network failure, or process restart.$q$, $q$Temporal Technologies was founded in 2019 by Maxim Fateev and Samar Abbas, who previously built the Cadence workflow engine at Uber and worked on earlier orchestration systems at AWS (Simple Workflow Service) and Microsoft (Azure Durable Functions). The company is headquartered in Seattle, Washington, and has raised roughly 350 million dollars in funding at a valuation of approximately 1.72 billion dollars.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Workflows and Activities are the core building blocks: a Workflow orchestrates one or more Activities, which are functions that interact with external systems such as APIs, databases, or other services.$q$, $q$Temporal maintains a complete Event History of every step in a workflow's execution, which the service uses to replay and resume workflows precisely after any failure, without lost progress or orphaned processes.$q$, $q$The platform offers official SDKs for Go, Java, TypeScript, Python, PHP, Ruby, and .NET, and supports polyglot use, letting different services within the same organization use different languages against the same Temporal service.$q$, $q$Temporal supports long-running and human-in-the-loop workflows through Signals, Queries, and Updates, making it suitable for processes that can span minutes, days, or months, including increasingly common AI agent orchestration use cases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Temporal's core server is free and open source under the MIT license, and organizations can self-host it at no licensing cost, though they take on the operational burden of running and scaling the service themselves.$q$, $q$Temporal Cloud is the managed alternative, priced across four tiers: Essentials starts at about 100 dollars per month and includes an allotment such as 1 million Actions, 1 GB of active storage, and 40 GB of retained storage; Business starts at about 500 dollars per month with higher included usage and support. Enterprise and Mission Critical tiers are custom-priced for large-scale or compliance-sensitive deployments. Usage beyond included allowances is billed at roughly 50 dollars per million Actions, and Temporal offers 1,000 dollars in free trial credits, plus up to 6,000 dollars in credits for early-stage startups.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2efa5f1f-29da-4d6c-a300-8437c5445f15', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
